roots = [Path('src'), Path('docs'), Path('tests')]
needles = ['EXPORTED_OPERATOR_PROMPT', 'operator_profile', 'tp series exec', 'tp series status', 'tp series finalize', 'TaskPacket', 'dopetask init']
